;◆イベント◆

; 初期発生イベント
events = [1, 2]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@se f=kacha
@wait time=800
@se f=fence
@switchfence x=0 y=0 way=e mode=open
@wait time=800
@notice text="I heard a door open somewhere!"
@delevent

[eventoff]
